<template>
	<div ref="wrapRef" :class="`pc-card-wrapper ${className}`.trim()" :style="cardStyle">
		<section ref="cardRef" class="pc-card">
			<div class="pc-inside">
				<div class="pc-shine" />

				<div class="pc-glare" />

				<div class="pc-content pc-avatar-content">
					<img
						class="avatar"
						:src="avatarUrl"
						:alt="`${name || 'User'} avatar`"
						loading="lazy"
						@error="handleAvatarError"
					>

					<div v-if="showUserInfo" class="pc-user-info">
						<div class="pc-user-details">
							<div class="pc-mini-avatar">
								<img
									:src="miniAvatarUrl || avatarUrl"
									:alt="`${name || 'User'} mini avatar`"
									loading="lazy"
									@error="handleMiniAvatarError"
								>
							</div>

							<div class="pc-user-text">
								<div class="pc-handle">
									@{{ handle }}
								</div>

								<div class="pc-status">
									{{ status }}
								</div>
							</div>
						</div>

						<button
							class="pc-contact-btn"
							style="pointer-events: auto"
							type="button"
							:aria-label="`Contact ${name || 'user'}`"
							@click="handleContactClick"
						>
							{{ contactText }}
						</button>
					</div>
				</div>

				<div class="pc-content">
					<div class="pc-details">
						<h3>{{ name }}</h3>

						<p>{{ title }}</p>
					</div>
				</div>
			</div>
		</section>
	</div>
</template>

<script setup>
import { computed, onMounted, onUnmounted, ref } from "vue";
const props = defineProps({
  avatarUrl: { type: String, required: false, default: "<Placeholder for avatar URL>" },
  iconUrl: { type: String, required: false, default: "<Placeholder for icon URL>" },
  grainUrl: { type: String, required: false, default: "<Placeholder for grain URL>" },
  behindGradient: { type: String, required: false, default: void 0 },
  innerGradient: { type: String, required: false, default: void 0 },
  showBehindGradient: { type: Boolean, required: false, default: true },
  className: { type: String, required: false, default: "" },
  enableTilt: { type: Boolean, required: false, default: true },
  miniAvatarUrl: { type: String, required: false, default: void 0 },
  name: { type: String, required: false, default: "Javi A. Torres" },
  title: { type: String, required: false, default: "Software Engineer" },
  handle: { type: String, required: false, default: "javicodes" },
  status: { type: String, required: false, default: "Online" },
  contactText: { type: String, required: false, default: "Contact" },
  showUserInfo: { type: Boolean, required: false, default: true }
});
const emit = defineEmits(["contactClick"]);
const wrapRef = ref();
const cardRef = ref();
const DEFAULT_BEHIND_GRADIENT = "radial-gradient(farthest-side circle at var(--pointer-x) var(--pointer-y),hsla(266,100%,90%,var(--card-opacity)) 4%,hsla(266,50%,80%,calc(var(--card-opacity)*0.75)) 10%,hsla(266,25%,70%,calc(var(--card-opacity)*0.5)) 50%,hsla(266,0%,60%,0) 100%),radial-gradient(35% 52% at 55% 20%,#00ffaac4 0%,#073aff00 100%),radial-gradient(100% 100% at 50% 50%,#00c1ffff 1%,#073aff00 76%),conic-gradient(from 124deg at 50% 50%,#c137ffff 0%,#07c6ffff 40%,#07c6ffff 60%,#c137ffff 100%)";
const DEFAULT_INNER_GRADIENT = "linear-gradient(145deg,#60496e8c 0%,#71C4FF44 100%)";
const ANIMATION_CONFIG = {
  SMOOTH_DURATION: 600,
  INITIAL_DURATION: 1500,
  INITIAL_X_OFFSET: 70,
  INITIAL_Y_OFFSET: 60
};
const clamp = (value, min = 0, max = 100) => Math.min(Math.max(value, min), max);
const round = (value, precision = 3) => Number.parseFloat(value.toFixed(precision));
const adjust = (value, fromMin, fromMax, toMin, toMax) => round(toMin + (toMax - toMin) * (value - fromMin) / (fromMax - fromMin));
const easeInOutCubic = (x) => x < 0.5 ? 4 * x * x * x : 1 - (-2 * x + 2) ** 3 / 2;
let rafId = null;
const updateCardTransform = (offsetX, offsetY, card, wrap) => {
  const width = card.clientWidth;
  const height = card.clientHeight;
  const percentX = clamp(100 / width * offsetX);
  const percentY = clamp(100 / height * offsetY);
  const centerX = percentX - 50;
  const centerY = percentY - 50;
  const properties = {
    "--pointer-x": `${percentX}%`,
    "--pointer-y": `${percentY}%`,
    "--background-x": `${adjust(percentX, 0, 100, 35, 65)}%`,
    "--background-y": `${adjust(percentY, 0, 100, 35, 65)}%`,
    "--pointer-from-center": `${clamp(Math.hypot(percentY - 50, percentX - 50) / 50, 0, 1)}`,
    "--pointer-from-top": `${percentY / 100}`,
    "--pointer-from-left": `${percentX / 100}`,
    "--rotate-x": `${round(-(centerX / 5))}deg`,
    "--rotate-y": `${round(centerY / 4)}deg`
  };
  Object.entries(properties).forEach(([property, value]) => {
    wrap.style.setProperty(property, value);
  });
};
const createSmoothAnimation = (duration, startX, startY, card, wrap) => {
  const startTime = performance.now();
  const targetX = wrap.clientWidth / 2;
  const targetY = wrap.clientHeight / 2;
  const animationLoop = (currentTime) => {
    const elapsed = currentTime - startTime;
    const progress = clamp(elapsed / duration);
    const easedProgress = easeInOutCubic(progress);
    const currentX = adjust(easedProgress, 0, 1, startX, targetX);
    const currentY = adjust(easedProgress, 0, 1, startY, targetY);
    updateCardTransform(currentX, currentY, card, wrap);
    if (progress < 1) {
      rafId = requestAnimationFrame(animationLoop);
    }
  };
  rafId = requestAnimationFrame(animationLoop);
};
const cancelAnimation = () => {
  if (rafId) {
    cancelAnimationFrame(rafId);
    rafId = null;
  }
};
const handlePointerMove = (event) => {
  const card = cardRef.value;
  const wrap = wrapRef.value;
  if (!card || !wrap || !props.enableTilt) return;
  const rect = card.getBoundingClientRect();
  updateCardTransform(event.clientX - rect.left, event.clientY - rect.top, card, wrap);
};
const handlePointerEnter = () => {
  const card = cardRef.value;
  const wrap = wrapRef.value;
  if (!card || !wrap || !props.enableTilt) return;
  cancelAnimation();
  wrap.classList.add("active");
  card.classList.add("active");
};
const handlePointerLeave = (event) => {
  const card = cardRef.value;
  const wrap = wrapRef.value;
  if (!card || !wrap || !props.enableTilt) return;
  createSmoothAnimation(ANIMATION_CONFIG.SMOOTH_DURATION, event.offsetX, event.offsetY, card, wrap);
  wrap.classList.remove("active");
  card.classList.remove("active");
};
const cardStyle = computed(() => ({
  "--icon": props.iconUrl ? `url(${props.iconUrl})` : "none",
  "--grain": props.grainUrl ? `url(${props.grainUrl})` : "none",
  "--behind-gradient": props.showBehindGradient ? props.behindGradient ?? DEFAULT_BEHIND_GRADIENT : "none",
  "--inner-gradient": props.innerGradient ?? DEFAULT_INNER_GRADIENT
}));
const handleContactClick = () => {
  emit("contactClick");
};
const handleAvatarError = (event) => {
  const target = event.target;
  target.style.display = "none";
};
const handleMiniAvatarError = (event) => {
  const target = event.target;
  target.style.opacity = "0.5";
  target.src = props.avatarUrl;
};
onMounted(() => {
  if (!props.enableTilt) return;
  const card = cardRef.value;
  const wrap = wrapRef.value;
  if (!card || !wrap) return;
  card.addEventListener("pointerenter", handlePointerEnter);
  card.addEventListener("pointermove", handlePointerMove);
  card.addEventListener("pointerleave", handlePointerLeave);
  const initialX = wrap.clientWidth - ANIMATION_CONFIG.INITIAL_X_OFFSET;
  const initialY = ANIMATION_CONFIG.INITIAL_Y_OFFSET;
  updateCardTransform(initialX, initialY, card, wrap);
  createSmoothAnimation(ANIMATION_CONFIG.INITIAL_DURATION, initialX, initialY, card, wrap);
});
onUnmounted(() => {
  const card = cardRef.value;
  if (card) {
    card.removeEventListener("pointerenter", handlePointerEnter);
    card.removeEventListener("pointermove", handlePointerMove);
    card.removeEventListener("pointerleave", handlePointerLeave);
  }
  cancelAnimation();
});
</script>

